      TOUCH TARGET MINIMUM
      ======================================== */
   --touch-target-min: 44px;
+
+  /* ========================================
+     Z-INDEX SCALE (Layering System)
+     ======================================== */
+  --z-base: 0;
+  --z-above: 10;
+  --z-dropdown: 20;
+  --z-sticky: 30;
+  --z-overlay: 40;
+  --z-modal: 50;
+  --z-popover: 60;
+  --z-tooltip: 70;
+  --z-toast: 80;
+  --z-max: 9999;
+
+  /* ========================================
+     BACKDROP BLUR SCALE
+     ======================================== */
+  --blur-sm: 8px;
+  --blur-md: 12px;
+  --blur-lg: 16px;
+  --blur-xl: 24px;
 }

